    [HttpGet]
    public async Task<IActionResult> SearchUsersByEmail([FromQuery] string email)
    {
        if (string.IsNullOrWhiteSpace(email))
        {
            return BadRequest("Email parameter cannot be empty.");
        }

        var users = new List<User>();

        using (var connection = new SqlConnection(_connectionString))
        {
            await connection.OpenAsync();
            var sql = "SELECT Id, FirstName, LastName, Email FROM Users WHERE Email LIKE @EmailSearch";

            using (var command = new SqlCommand(sql, connection))
            {
                command.Parameters.AddWithValue("@EmailSearch", $"%{email}%");

                using (var reader = await command.ExecuteReaderAsync())
                {
                    while (await reader.ReadAsync())
                    {
                        users.Add(new User
                        {
                            Id = reader.GetInt32(reader.GetOrdinal("Id")),
                            FirstName = reader.GetString(reader.GetOrdinal("FirstName")),
                            LastName = reader.GetString(reader.GetOrdinal("LastName")),
                            Email = reader.GetString(reader.GetOrdinal("Email"))
                        });
                    }
                }
            }
        }

        if (users.Any())
        {
            return Ok(users);
        }
        else
        {
            return NotFound("No users found matching the provided email.");
        }
    }
}

